// Server-only SQLite database wrapper for the products catalog.
// This module must only be imported from server-only code (e.g. inside a
// `routeLoader$`). It is intentionally not referenced from any client component.

import Database from "better-sqlite3";
import type { Database as DatabaseT } from "better-sqlite3";
import { readFileSync, existsSync, mkdirSync } from "node:fs";
import { join } from "node:path";

export interface Product {
  id: number;
  name: string;
  category: string;
  price: number;
  stock: number;
}

export interface QueryParams {
  q: string;
  sort: string;
  dir: string;
  page: number;
  pageSize: number;
}

export interface QueryResult {
  rows: Product[];
  total: number;
}

const VALID_SORTS = new Set(["name", "category", "price", "stock"]);
const VALID_DIRS = new Set(["asc", "desc"]);
const DEFAULT_SORT = "name";
const DEFAULT_DIR = "asc";
const DEFAULT_PAGE = 1;
const DEFAULT_PAGE_SIZE = 10;
const MAX_PAGE_SIZE = 100;

let dbInstance: DatabaseT | null = null;
let initPromise: Promise<DatabaseT> | null = null;

function dataPaths() {
  // Use the working directory because `npm run dev` is always started from
  // the project root (`/home/user/app`), where `data/products.json` lives.
  const dataDir = join(process.cwd(), "data");
  return {
    dataDir,
    dbPath: join(dataDir, "products.db"),
    jsonPath: join(dataDir, "products.json"),
  };
}

async function loadProducts(jsonPath: string): Promise<Product[]> {
  const raw = await readFileSync(jsonPath, "utf-8");
  const parsed = JSON.parse(raw);
  if (!Array.isArray(parsed)) {
    throw new Error("products.json must be an array");
  }
  return parsed as Product[];
}

async function initDatabase(): Promise<DatabaseT> {
  if (dbInstance) return dbInstance;
  if (initPromise) return initPromise;

  initPromise = (async () => {
    const { dataDir, dbPath, jsonPath } = dataPaths();
    if (!existsSync(dataDir)) {
      mkdirSync(dataDir, { recursive: true });
    }

    const db = new Database(dbPath);
    db.pragma("journal_mode = WAL");

    db.exec(`
      CREATE TABLE IF NOT EXISTS products (
        id INTEGER PRIMARY KEY,
        name TEXT NOT NULL,
        category TEXT NOT NULL,
        price REAL NOT NULL,
        stock INTEGER NOT NULL
      );
      CREATE INDEX IF NOT EXISTS idx_products_name ON products(name);
      CREATE INDEX IF NOT EXISTS idx_products_category ON products(category);
      CREATE INDEX IF NOT EXISTS idx_products_price ON products(price);
      CREATE INDEX IF NOT EXISTS idx_products_stock ON products(stock);
    `);

    const countRow = db
      .prepare("SELECT COUNT(*) as c FROM products")
      .get() as { c: number };

    if (countRow.c === 0) {
      const products = await loadProducts(jsonPath);
      const insert = db.prepare(
        "INSERT INTO products (id, name, category, price, stock) VALUES (@id, @name, @category, @price, @stock)",
      );
      const insertMany = db.transaction((items: Product[]) => {
        for (const p of items) {
          insert.run({
            id: p.id,
            name: p.name,
            category: p.category,
            price: p.price,
            stock: p.stock,
          });
        }
      });
      insertMany(products);
    }

    dbInstance = db;
    return db;
  })();

  return initPromise;
}

async function getDb(): Promise<DatabaseT> {
  if (dbInstance) return dbInstance;
  return initDatabase();
}

export async function queryProducts(params: QueryParams): Promise<QueryResult> {
  const db = await getDb();

  const sort = VALID_SORTS.has(params.sort) ? params.sort : DEFAULT_SORT;
  const dir = VALID_DIRS.has(params.dir) ? params.dir : DEFAULT_DIR;
  const rawPage = Number.isFinite(params.page)
    ? Math.floor(params.page)
    : DEFAULT_PAGE;
  const page = Math.max(1, rawPage);
  const rawPageSize = Number.isFinite(params.pageSize)
    ? Math.floor(params.pageSize)
    : DEFAULT_PAGE_SIZE;
  const pageSize = Math.min(MAX_PAGE_SIZE, Math.max(1, rawPageSize));
  const offset = (page - 1) * pageSize;

  const whereClauses: string[] = [];
  const whereArgs: (string | number)[] = [];

  const trimmedQ = params.q ? params.q.trim() : "";
  if (trimmedQ) {
    whereClauses.push("LOWER(name) LIKE ?");
    whereArgs.push(`%${trimmedQ.toLowerCase()}%`);
  }

  const whereSql = whereClauses.length
    ? `WHERE ${whereClauses.join(" AND ")}`
    : "";
  const dirSql = dir === "asc" ? "ASC" : "DESC";
  // `sort` is whitelisted above so it is safe to interpolate as a column name.
  const orderSql = `ORDER BY ${sort} ${dirSql}`;

  const countSql = `SELECT COUNT(*) as c FROM products ${whereSql}`;
  const dataSql = `SELECT id, name, category, price, stock FROM products ${whereSql} ${orderSql} LIMIT ? OFFSET ?`;

  const countRow = db.prepare(countSql).get(...whereArgs) as { c: number };
  const rows = db
    .prepare(dataSql)
    .all(...whereArgs, pageSize, offset) as Product[];

  return {
    rows,
    total: countRow.c,
  };
}

import { component$, useSignal, useTask$, $ } from "@builder.io/qwik";
import {
  routeLoader$,
  Link,
  useNavigate,
  type DocumentHead,
} from "@builder.io/qwik-city";
import { queryProducts, type Product } from "~/lib/db";

const VALID_SORTS = new Set(["name", "category", "price", "stock"]);
const VALID_DIRS = new Set(["asc", "desc"]);

export const useProductsData = routeLoader$(async (event) => {
  const sp = event.url.searchParams;
  const q = sp.get("q") ?? "";
  const sortRaw = sp.get("sort") ?? "name";
  const dirRaw = sp.get("dir") ?? "asc";
  const pageRaw = sp.get("page") ?? "1";
  const pageSizeRaw = sp.get("pageSize") ?? "10";

  const sort = VALID_SORTS.has(sortRaw) ? sortRaw : "name";
  const dir = VALID_DIRS.has(dirRaw) ? dirRaw : "asc";
  const pageSizeRawNum = Number(pageSizeRaw);
  const pageSize = Number.isFinite(pageSizeRawNum)
    ? Math.min(100, Math.max(1, Math.floor(pageSizeRawNum)))
    : 10;
  const pageRawNum = Number(pageRaw);
  const page = Number.isFinite(pageRawNum)
    ? Math.max(1, Math.floor(pageRawNum))
    : 1;

  const { rows, total } = await queryProducts({
    q,
    sort,
    dir,
    page,
    pageSize,
  });
  const totalPages = Math.max(1, Math.ceil(total / pageSize));

  return {
    rows,
    total,
    page,
    pageSize,
    totalPages,
    sort,
    dir,
    q,
  };
});

function buildHref(
  current: {
    q: string;
    sort: string;
    dir: string;
    page: number;
    pageSize: number;
  },
  overrides: Partial<{
    q: string | null;
    sort: string;
    dir: string;
    page: number | null;
    pageSize: number;
  }> = {},
): string {
  const params = new URLSearchParams();
  const finalQ = overrides.q === null ? "" : overrides.q ?? current.q;
  const finalSort = overrides.sort ?? current.sort;
  const finalDir = overrides.dir ?? current.dir;
  const finalPage =
    overrides.page === null ? 1 : overrides.page ?? current.page;
  const finalPageSize = overrides.pageSize ?? current.pageSize;

  if (finalQ) params.set("q", finalQ);
  if (finalSort && finalSort !== "name") params.set("sort", finalSort);
  if (finalDir && finalDir !== "asc") params.set("dir", finalDir);
  if (finalPage && finalPage !== 1) params.set("page", String(finalPage));
  if (finalPageSize && finalPageSize !== 10) {
    params.set("pageSize", String(finalPageSize));
  }

  const qs = params.toString();
  return qs ? `/products?${qs}` : "/products";
}

export default component$(() => {
  const data = useProductsData();
  const nav = useNavigate();
  const searchInput = useSignal(data.value.q);

  // Debounce the search input (~300ms) and update only the `q` query param.
  // Other state (sort/dir/page) is preserved.
  useTask$(({ track, cleanup }) => {
    const v = track(() => searchInput.value);
    if (typeof window === "undefined") return;
    if (v === data.value.q) return;

    const handle = setTimeout(() => {
      const params = new URLSearchParams(window.location.search);
      if (v) {
        params.set("q", v);
      } else {
        params.delete("q");
      }
      // Reset to page 1 for a new query so the user sees the first page
      // of matching results.
      params.set("page", "1");
      // Preserve sort/dir.
      params.set("sort", data.value.sort);
      params.set("dir", data.value.dir);
      const qs = params.toString();
      nav(qs ? `/products?${qs}` : "/products", { replaceState: true });
    }, 300);

    cleanup(() => clearTimeout(handle));
  });

  const { rows, total, page, totalPages, sort, dir, q } = data.value;

  return (
    <div class="products-page">
      <h1>Products</h1>

      <div class="toolbar">
        <input
          type="search"
          aria-label="Search products by name"
          placeholder="Search products by name..."
          value={searchInput.value}
          onInput$={(_, el) => {
            searchInput.value = (el as HTMLInputElement).value;
          }}
        />
        <noscript>
          <style
            dangerouslySetInnerHTML={`
              /* When JS is disabled, the search box still submits via Enter
                 so users have a way to filter. */
            `}
          />
        </noscript>
      </div>

      <p class="meta">
        <span>Total: {total}</span>{" "}
        <span>
          Page {page} of {totalPages}
        </span>
      </p>

      <table>
        <thead>
          <tr>
            <th>
              <Link
                href={buildHref(
                  { q, sort, dir, page, pageSize: data.value.pageSize },
                  {
                    sort: "name",
                    dir:
                      sort === "name" && dir === "asc" ? "desc" : "asc",
                    page: 1,
                  },
                )}
              >
                Name{sort === "name" ? (dir === "asc" ? " ▲" : " ▼") : ""}
              </Link>
            </th>
            <th>
              <Link
                href={buildHref(
                  { q, sort, dir, page, pageSize: data.value.pageSize },
                  {
                    sort: "category",
                    dir:
                      sort === "category" && dir === "asc"
                        ? "desc"
                        : "asc",
                    page: 1,
                  },
                )}
              >
                Category
                {sort === "category" ? (dir === "asc" ? " ▲" : " ▼") : ""}
              </Link>
            </th>
            <th>
              <Link
                href={buildHref(
                  { q, sort, dir, page, pageSize: data.value.pageSize },
                  {
                    sort: "price",
                    dir:
                      sort === "price" && dir === "asc" ? "desc" : "asc",
                    page: 1,
                  },
                )}
              >
                Price{sort === "price" ? (dir === "asc" ? " ▲" : " ▼") : ""}
              </Link>
            </th>
            <th>
              <Link
                href={buildHref(
                  { q, sort, dir, page, pageSize: data.value.pageSize },
                  {
                    sort: "stock",
                    dir:
                      sort === "stock" && dir === "asc" ? "desc" : "asc",
                    page: 1,
                  },
                )}
              >
                Stock{sort === "stock" ? (dir === "asc" ? " ▲" : " ▼") : ""}
              </Link>
            </th>
          </tr>
        </thead>
        <tbody>
          {rows.map((p: Product) => (
            <tr key={p.id}>
              <td>{p.name}</td>
              <td>{p.category}</td>
              <td>{p.price}</td>
              <td>{p.stock}</td>
            </tr>
          ))}
        </tbody>
      </table>

      <nav class="pagination" aria-label="Pagination">
        {page > 1 ? (
          <Link
            href={buildHref(
              { q, sort, dir, page, pageSize: data.value.pageSize },
              { page: page - 1 },
            )}
            class="prev"
            rel="prev"
          >
            ‹ Previous
          </Link>
        ) : (
          <span class="prev disabled" aria-disabled="true">
            ‹ Previous
          </span>
        )}
        <span class="page-indicator">
          Page {page} of {totalPages}
        </span>
        {page < totalPages ? (
          <Link
            href={buildHref(
              { q, sort, dir, page, pageSize: data.value.pageSize },
              { page: page + 1 },
            )}
            class="next"
            rel="next"
          >
            Next ›
          </Link>
        ) : (
          <span class="next disabled" aria-disabled="true">
            Next ›
          </span>
        )}
      </nav>
    </div>
  );
});

export const head: DocumentHead = {
  title: "Products",
  meta: [
    {
      name: "description",
      content: "Browse, sort, search, and paginate the product catalog.",
    },
  ],
};

